        ]
      },
      "notes": "Tests a valid search for late deliverables."
    },
    {
      "name": "no_late_deliverables_found",
      "input": {
        "search_query": "non_existent_project_id"
      },
      "output": {
        "status": "success",
        "data": []
      },
      "notes": "Tests the case where no late deliverables are found."
    },
    {
      "name": "expand_late_deliverable",
      "input": {
        "deliverable_id": 1
      },
      "output": {
        "status": "success",
        "data": {
          "id": 1,
          "project_id": "valid_project_id",
          "status": "late",
          "details": "Expanded deliverable details here"
        }
      },
      "notes": "Tests expanding a valid late deliverable."
    },
    {
      "name": "edit_late_deliverable",
      "input": {
        "deliverable_id": 1,
        "update_data": {
          "status": "on_time",
          "details": "Updated deliverable details"
        }
      },
      "output": {
        "status": "success",
        "message": "Deliverable updated successfully"
      },
      "notes": "Tests editing a late deliverable."
    },
    {
      "name": "invalid_deliverable_id",
      "input": {
        "deliverable_id": 9999
      },
      "output": {
        "status": "error",
        "message": "Deliverable not found"
      },
      "notes": "Tests handling of an invalid deliverable ID."
    },
    {
      "name": "sql_injection_attempt",
      "input": {
        "search_query": "'; DROP TABLE deliverables; --"
      },
      "output": {
        "status": "error",
        "message": "Invalid search query"
      },
      "notes": "Tests for SQL injection vulnerability."
    },
    {
      "name": "empty_search_query",
      "input": {
        "search_query": ""
      },
      "output": {
        "status": "error",
        "message": "Search query cannot be empty"
      },
      "notes": "Tests handling of an empty search query."
    },
    {
      "name": "large_data_set",
      "input": {
        "search_query": "large_project_id"
      },
      "output": {
        "status": "success",
        "data": [
          // Simulating a large number of deliverables
          {"id": 1, "status": "late"},
